-- POSTGIS GEOSPATIAL INDICES (if extension is available) ───────────────

DO $$ BEGIN
  PERFORM 1 FROM pg_extension WHERE extname = 'postgis';
EXCEPTION WHEN OTHERS THEN NULL; END $$;
--> statement-breakpoint

DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'postgis') THEN
    EXECUTE 'CREATE INDEX IF NOT EXISTS idx_ride_drivers_postgis ON ride_drivers USING gist (ll_to_earth(current_lat::float8, current_lng::float8))';
    EXECUTE 'CREATE INDEX IF NOT EXISTS idx_ride_requests_pickup_postgis ON ride_requests USING gist (ll_to_earth(pickup_lat::float8, pickup_lng::float8))';
    EXECUTE 'CREATE INDEX IF NOT EXISTS idx_ride_requests_dropoff_postgis ON ride_requests USING gist (ll_to_earth(dropoff_lat::float8, dropoff_lng::float8))';
    EXECUTE 'CREATE INDEX IF NOT EXISTS idx_ride_places_postgis ON ride_places USING gist (ll_to_earth(lat::float8, lng::float8))';
    EXECUTE 'CREATE INDEX IF NOT EXISTS idx_ride_heatmap_postgis ON ride_heatmap_predictions USING gist (ll_to_earth(lat::float8, lng::float8))';
  END IF;
END $$;
--> statement-breakpoint

