-- RLS policies: drivers see their own row, riders see their own rides,
-- curators see their campus data. Admin role bypasses RLS entirely.

DO $$ BEGIN
  CREATE POLICY "ride_drivers_self_select" ON "ride_drivers"
    FOR SELECT USING (auth.uid() = user_id);
EXCEPTION WHEN duplicate_object THEN NULL; END $$;
--> statement-breakpoint

DO $$ BEGIN
  CREATE POLICY "ride_requests_rider_select" ON "ride_requests"
    FOR SELECT USING (auth.uid() = rider_id);
EXCEPTION WHEN duplicate_object THEN NULL; END $$;
--> statement-breakpoint

DO $$ BEGIN
  CREATE POLICY "ride_requests_driver_select" ON "ride_requests"
    FOR SELECT USING (
      EXISTS (
        SELECT 1 FROM ride_drivers d
        WHERE d.id = ride_requests.driver_id AND d.user_id = auth.uid()
      )
    );
EXCEPTION WHEN duplicate_object THEN NULL; END $$;
--> statement-breakpoint

DO $$ BEGIN
  CREATE POLICY "ride_user_places_owner" ON "ride_user_places"
    FOR ALL USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);
EXCEPTION WHEN duplicate_object THEN NULL; END $$;
--> statement-breakpoint

DO $$ BEGIN
  CREATE POLICY "ride_rewards_owner" ON "ride_rewards"
    FOR SELECT USING (auth.uid() = user_id);
EXCEPTION WHEN duplicate_object THEN NULL; END $$;
--> statement-breakpoint

DO $$ BEGIN
  CREATE POLICY "ride_curators_campus_read" ON "ride_curators"
    FOR SELECT USING (true);
EXCEPTION WHEN duplicate_object THEN NULL; END $$;
--> statement-breakpoint

DO $$ BEGIN
  CREATE POLICY "ride_curator_lb_public" ON "ride_curator_leaderboard"
    FOR SELECT USING (true);
EXCEPTION WHEN duplicate_object THEN NULL; END $$;
--> statement-breakpoint

DO $$ BEGIN
  CREATE POLICY "ride_ratings_public" ON "ride_ratings"
    FOR SELECT USING (is_public = true);
EXCEPTION WHEN duplicate_object THEN NULL; END $$;
--> statement-breakpoint

-- SEED ANCHOR: a system row for audit log to reference when no actor is
-- known (e.g. background job cancelling a stale ride).

INSERT INTO "ride_audit_logs" ("actor_id", "actor_role", "action", "entity", "entity_id", "before", "after", "ip_address", "user_agent", "created_at")
SELECT NULL, 'system', 'migration:0002_ride_and_go', 'schema', NULL, NULL, '{"applied":true}', '127.0.0.1', 'drizzle-kit/0002_ride_and_go',
       now()
WHERE NOT EXISTS (SELECT 1 FROM "ride_audit_logs" WHERE "action" = 'migration:0002_ride_and_go');
--> statement-breakpoint